1	// MHPCO Claim Office - Policy quoting and claim processing system
2	
3	const ITEM_TYPE_PREMIUMS: Record<string, number> = {
4	  Sword: 50,
5	  Amulet: 100,
6	  Staff: 75,
7	  Potion: 60,
8	};
9	
10	const FIRST_INSURANCE_SURCHARGE = 1.1;
11	const LOYALTY_DISCOUNT = 0.8; // -20% discount for 2+ years
12	const CURSED_ITEM_SURCHARGE = 1.5;
13	const HIGH_ENCHANTMENT_SURCHARGE = 1.3; // +30% for enchantmentLevel >= 5
14	
15	export interface Item {
16	  type: string;
17	  insuranceModifier?: string;
18	  yearsInsured?: number;
19	  cursed?: boolean;
20	  enchantmentLevel?: number;
21	}
22	
23	const applyModifier = (value: number, multiplier: number, shouldApply: boolean): number => {
24	  return shouldApply ? value * multiplier : value;
25	};
26	
27	const applyModifiers = (premium: number, item: Item): number => {
28	  let adjusted = premium;
29	
30	  // Apply first insurance surcharge
31	  adjusted = applyModifier(adjusted, FIRST_INSURANCE_SURCHARGE, item.insuranceModifier === "first");
32	
33	  // Apply loyalty discount
34	  adjusted = applyModifier(adjusted, LOYALTY_DISCOUNT, item.yearsInsured !== undefined && item.yearsInsured >= 2);
35	
36	  // Apply cursed surcharge
37	  adjusted = applyModifier(adjusted, CURSED_ITEM_SURCHARGE, item.cursed === true);
38	
39	  // Apply enchantment surcharge
40	  adjusted = applyModifier(adjusted, HIGH_ENCHANTMENT_SURCHARGE, item.enchantmentLevel !== undefined && item.enchantmentLevel >= 5);
41	
42	  return adjusted;
43	};
44	
45	const roundUpInMHPCOsFavor = (value: number): number => {
46	  const standardRound = Math.round(value);
47	  return value > standardRound ? standardRound + 1 : standardRound;
48	};
49	
50	export function quotePolicy(items: Item[]): number {
51	  const total = items.reduce((sum, item) => {
52	    if (!(item.type in ITEM_TYPE_PREMIUMS)) {
53	      throw new Error(`Unknown item type: ${item.type}`);
54	    }
55	    const basePremium = ITEM_TYPE_PREMIUMS[item.type];
56	    const adjustedPremium = applyModifiers(basePremium, item);
57	    return sum + Math.round(adjustedPremium * 100) / 100;
58	  }, 0);
59	  return roundUpInMHPCOsFavor(total);
60	}
61	
62	const INDIVIDUAL_COMPONENT_PRICE = 25;
63	const COMPONENT_BLOCK_SIZE = 3;
64	const COMPONENT_BLOCK_PRICE = 60;
65	
66	const CLAIM_DEDUCTIBLE = 100;
67	const INSURANCE_CAP_MULTIPLIER = 2;
68	const HIGH_ENCHANTMENT_REIMBURSEMENT_THRESHOLD = 8;
69	const HIGH_ENCHANTMENT_REIMBURSEMENT_RATE = 0.5;
70	
71	export function quoteComponent(items: Item[]): number {
72	  return items.length === COMPONENT_BLOCK_SIZE ? COMPONENT_BLOCK_PRICE : INDIVIDUAL_COMPONENT_PRICE;
73	}
74	
75	const applyInsuranceCap = (amount: number, insuranceSum: number, dragonMaterial: boolean): number => {
76	  if (dragonMaterial) {
77	    return amount;
78	  }
79	  const cap = insuranceSum * INSURANCE_CAP_MULTIPLIER;
80	  return Math.min(amount, cap);
81	};
82	
83	const applyEnchantmentReduction = (reimbursement: number, enchantmentLevel?: number): number => {
84	  if (enchantmentLevel !== undefined && enchantmentLevel >= HIGH_ENCHANTMENT_REIMBURSEMENT_THRESHOLD) {
85	    return reimbursement * HIGH_ENCHANTMENT_REIMBURSEMENT_RATE;
86	  }
87	  return reimbursement;
88	};
89	
90	export function processClaim(damage: number, insuranceSum?: number, enchantmentLevel?: number, dragonMaterial?: boolean): number {
91	  if (damage === 0) {
92	    return 0;
93	  }
94	  const afterDeductible = damage - CLAIM_DEDUCTIBLE;
95	  if (insuranceSum !== undefined) {
96	    const cappedAmount = applyInsuranceCap(afterDeductible, insuranceSum, dragonMaterial ?? false);
97	    return applyEnchantmentReduction(cappedAmount, enchantmentLevel);
98	  }
99	  return afterDeductible;
100	}
